const fs = require('fs');

let html = fs.readFileSync('About us.html', 'utf-8');

// Find the <main> element
let mainStart = html.indexOf('<main');
let mainEnd = html.indexOf('</main>') + 7;

// Find all <style> blocks in head
let styles = '';
let styleRegex = /<style\b[^>]*>([\s\S]*?)<\/style>/gi;
let match;
while ((match = styleRegex.exec(html)) !== null) {
    styles += match[0] + '\n';
}

// Find all <link rel="stylesheet"> blocks in head
let links = '';
let linkRegex = /<link[^>]*rel="stylesheet"[^>]*>/gi;
while ((match = linkRegex.exec(html)) !== null) {
    let l = match[0];
    l = l.replace(/\.\/About us_files\//g, '/photos/history/');
    links += l + '\n';
}

if (mainStart !== -1 && mainEnd !== -1) {
    let mainHtml = html.substring(mainStart, mainEnd);

    // Replace image paths
    mainHtml = mainHtml.replace(/\.\/About us_files\//g, '/photos/history/');

    // Remove scripts
    mainHtml = mainHtml.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');

    // Strip out animation classes
    mainHtml = mainHtml.replace(/data-aos="[^"]*"/g, '');
    mainHtml = mainHtml.replace(/xyz="[^"]*"/g, '');
    mainHtml = mainHtml.replace(/\bxyz-nested\b/g, '');
    mainHtml = mainHtml.replace(/\bxyz-in\b/g, '');

    let injectedHtml = `
      ${links}
      ${styles}
      ${mainHtml}
    `;

    // Use JSON.stringify to safely escape the HTML string
    let contentTs = `export const aboutHtml = ${JSON.stringify(injectedHtml)};\n`;
    fs.writeFileSync('../../../app/about/content.ts', contentTs);

